{"code":"from decimal import Decimal, ROUND_HALF_UP


def migrate(input_record: str) -> str:
    record = (input_record or "")
    if len(record) < 44:
        record = record.ljust(44)
    else:
        record = record[:44]

    def parse_int(s: str) -> int:
        s = s.strip()
        return int(s) if s else 0

    def parse_amount(s: str) -> Decimal:
        s = s.strip()
        if not s:
            return Decimal('0')
        # PIC 9(4)V99 => 6 implied-decimal digits, stored as fixed-width digits
        return Decimal(int(s)) / Decimal('100')

    invoice_id = record[0:6]
    item_count = max(0, min(parse_int(record[6:8]), 4))

    total = Decimal('0')
    for idx in range(item_count):
        base = 8 + idx * 9
        qty = parse_int(record[base:base + 2])
        price = parse_amount(record[base + 2:base + 8])
        taxable = record[base + 8:base + 9]

        line_amount = (Decimal(qty) * price).quantize(Decimal('0.01'), rounding=ROUND_HALF_UP)
        if taxable == 'Y':
            line_amount = (line_amount * Decimal('1.075')).quantize(Decimal('0.01'), rounding=ROUND_HALF_UP)
        total += line_amount

    total_cents = int(total.quantize(Decimal('0.01'), rounding=ROUND_HALF_UP) * 100)
    out_total = f"{total_cents:09d}"
    out_item_count = f"{item_count:02d}"
    out_flag = 'H' if item_count >= 4 else 'L'

    return f"{invoice_id}{out_total}{out_item_count}{out_flag}"
"}
